import React, { useEffect, useState } from 'react';
import './CommandeList.css';

function CommandeList() {
  const [commandes, setCommandes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedCommande, setSelectedCommande] = useState(null); // commande sélectionnée pour modifier

  const fetchCommandes = () => {
    setLoading(true);
    fetch('http://localhost:3001/commandes')
      .then(res => {
        if (!res.ok) throw new Error('Erreur lors du chargement des commandes');
        return res.json();
      })
      .then(data => {
        setCommandes(data);
        setError(null);
      })
      .catch(err => {
        console.error('Erreur chargement commandes:', err);
        setError(err.message);
      })
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    fetchCommandes();
  }, []);

  const handleDelete = async (idCOM) => {
    if (!window.confirm('Supprimer cette commande ?')) return;

    try {
      const res = await fetch(`http://localhost:3001/commandes/${idCOM}`, {
        method: 'DELETE'
      });
      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }
      fetchCommandes();  // refresh liste après suppression
      if (selectedCommande && selectedCommande.idCOM === idCOM) {
        setSelectedCommande(null);  // désélection si supprimé
      }
    } catch (err) {
      alert('Erreur lors de la suppression : ' + err.message);
    }
  };

  const handleEdit = (commande) => {
    setSelectedCommande(commande);
  };

  const handleFormSuccess = () => {
    setSelectedCommande(null); // reset formulaire après succès
    fetchCommandes();          // rafraîchir la liste
  };

  if (loading) return <p className="info-message">Chargement des commandes...</p>;
  if (error) return <p className="error-message">Erreur : {error}</p>;

  return (
    <div className="commande-list">
      <h2>Liste des Commandes</h2>
      {commandes.length === 0 ? (
        <p className="info-message">Aucune commande disponible.</p>
      ) : (
        <table>
          <thead>
            <tr>
              <th>ID</th>
              <th>Client</th>
              <th>Article</th>
              <th>Date</th>
              <th>Quantité</th>
              <th>Actions</th> {/* Colonne Actions */}
            </tr>
          </thead>
          <tbody>
            {commandes.map(cmd => (
              <tr key={cmd.idCOM}>
                <td>{cmd.idCOM}</td>
                <td>{cmd.nomCli || cmd.codeCli}</td>
                <td>{cmd.nomArt || cmd.codeArt}</td>
                <td>{cmd.dateCom}</td>
                <td>{cmd.QteCom}</td>
                <td>
                  <button onClick={() => handleEdit(cmd)}>Modifier</button>
                  <button onClick={() => handleDelete(cmd.idCOM)}>Supprimer</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default CommandeList;
